// Baut eine Discord Components v2 Message mit ActionRow + Inline-Buttons.
// Input-Schema (von discord_notify.py in ai-review-pipeline):
//   body.pr_number      string | number
//   body.pr_url         string (GitHub PR URL)
//   body.project        string (Projektname)
//   body.channel_id     string (Discord Channel ID)
//   body.stage          string (aktuell fehlgeschlagene Stage oder 'dispatch')
//   body.summary        string (max 500 Zeichen, Review-Summary)
//   body.avg_score      number (Consensus-Score 0-10)
//   body.button_actions array [{text, custom_id}] — optional, override Standard-Buttons
//
// Discord API v10: POST /channels/{channel_id}/messages
// flags: 32768 = IS_COMPONENTS_V2 (required für Components v2)
// Ref: https://discord.com/developers/docs/interactions/message-components

const body = $json.body ?? $json ?? {};

const prNumber  = String(body.pr_number ?? '?');
const prUrl     = String(body.pr_url ?? '');
const project   = String(body.project ?? 'unknown');
const channelId = String(body.channel_id ?? '');
const stage     = String(body.stage ?? 'dispatch');
const summary   = String(body.summary ?? '').slice(0, 500);
const avgScore  = body.avg_score ?? null;

if (!channelId) {
  throw new Error('channel_id fehlt im Payload. Bitte .ai-review/config.yaml prüfen.');
}

// --- Content ---
const scoreEmoji = avgScore === null ? '' : avgScore >= 8 ? '\u2705' : avgScore >= 5 ? '\u26a0\ufe0f' : '\u274c';
const scoreLine = avgScore !== null ? `${scoreEmoji} **Score:** ${avgScore}/10` : '';

let content = [
  `**AI-Review** \u2014 Projekt \`${project}\` \u2014 PR #${prNumber}`,
  scoreLine,
  stage !== 'dispatch' ? `**Stage:** ${stage}` : '',
  summary ? `**Summary:**\n\`\`\`\n${summary}\n\`\`\`` : '',
  prUrl ? `**PR:** ${prUrl}` : '',
].filter(Boolean).join('\n');

// --- Buttons ---
// Standard-Buttons wenn button_actions nicht im Payload
let buttons;
if (Array.isArray(body.button_actions) && body.button_actions.length > 0) {
  buttons = body.button_actions
    .filter(a => a && a.text && a.custom_id)
    .map(a => ({
      type: 2,           // BUTTON component type
      style: a.style ?? 1,  // 1=PRIMARY, 2=SECONDARY, 4=DANGER
      label: a.text,
      custom_id: a.custom_id,
    }));
} else {
  // Standard: Approve (PRIMARY=1), Auto-Fix (SECONDARY=2), Manual (DANGER=4)
  buttons = [
    { type: 2, style: 1, label: 'Approve',  custom_id: `approve:${prNumber}` },
    { type: 2, style: 2, label: 'Auto-Fix', custom_id: `fix:${prNumber}` },
    { type: 2, style: 4, label: 'Manual',   custom_id: `manual:${prNumber}` },
  ];
}

// --- Payload für Discord API ---
// flags: 32768 = IS_COMPONENTS_V2
const discordPayload = {
  content,
  components: [
    {
      type: 1,        // ACTION_ROW
      components: buttons,
    },
  ],
  flags: 32768,
};

return [{
  json: {
    channel_id: channelId,
    discord_payload: discordPayload,
    pr_number: prNumber,
    project,
  },
}];
